(function(window){window.PDFObject=window.PDFObject||{};PDFObject.embed=function(targetUrl,options){try{var iframe=document.createElement('iframe');iframe.style.border='0';iframe.style.width=(options&&options.width)||'100%';iframe.style.height=(options&&options.height)||'100%';iframe.src=targetUrl;document.body.appendChild(iframe);return true}catch(e){console.error('PDFObject stub failed to embed:',e);return false}};})(window);